Endpoint: POST /dms/{processId}
Summary: Upload a new document for signature
Description: Upload a new document for signature, while process is in state reviewed
Tags: dms
Request Body: {
  "content": {
    "application/json": {
      "schema": {
        "type": "array",
        "items": {
          "type": "object",
          "title": "Input document data",
          "required": [
            "type",
            "data",
            "id"
          ],
          "additionalProperties": false,
          "properties": {
            "id": {
              "type": "string",
              "title": "The id of the document",
              "example": "37283719273"
            },
            "type": {
              "type": "string",
              "title": "type of document, values are used to distinguish the document types",
              "default": "signature",
              "example": "contract"
            },
            "title": {
              "type": "string",
              "title": "The document title",
              "example": "Vorsorgevertrag"
            },
            "flatten": {
              "type": "boolean",
              "title": "If true, the document will be flattened. This means that all form fields will be removed and the document will be saved as a flat PDF. This is useful for signing documents that contain form fields.",
              "default": false
            },
            "data": {
              "type": "string",
              "title": "The document data (base64)",
              "example": "<base 64 string>"
            },
            "signature_position": {
              "oneOf": [
                {
                  "type": "object",
                  "title": "section to position the electronic signature",
                  "additionalProperties": false,
                  "properties": {
                    "x": {
                      "type": "number",
                      "title": "The x position from the left in user space units (distance in inch*72)",
                      "minimum": 0,
                      "maximum": 1125,
                      "example": 120
                    },
                    "y": {
                      "type": "number",
                      "title": "The y position from the top in user space units (distance in inch*72)",
                      "minimum": 0,
                      "maximum": 2436,
                      "example": 60
                    },
                    "page": {
                      "type": "number",
                      "title": "The page index, starting at 0 for first page. Use -1 to place the signature on the last page.",
                      "minimum": -1,
                      "maximum": 10000,
                      "example": 50
                    }
                  }
                },
                {
                  "type": "object",
                  "title": "Placeholder string to position the electronic signature. This feature is only available if \"Signature\" type is set in processSteps.",
                  "additionalProperties": false,
                  "properties": {
                    "placeholder": {
                      "type": "string",
                      "title": "Instead of coordinates and page number you can pass a placeholder string. The signature will be inserted at the first occurence of the placeholder in the pdf document. The placeholder in the pdf needs to be between 2 dollar signs: $$Signature-0001$$. However you must only pass the placeholder string to the request, without dollar signs. The placeholder in the pdf may also contain the desired width and height of the signature box as well as the desired signature text. Example1: $$Signature-0001,100,50$$ (Placeholdername, width, height) Example2: $$Signature-0001,100,50,Signed by John Doe$$ (Placeholdername, width, height, signature text).",
                      "example": "Signature-0001"
                    }
                  }
                }
              ]
            },
            "visualSignature": {
              "type": "object",
              "title": "section to define the visual size of the electronic signature",
              "additionalProperties": false,
              "properties": {
                "text": {
                  "type": "string",
                  "title": "The text that will be displayed on the signature. Supports the following placeholders: {{date}}, {{time}},  {{datetime}} with optional format {{date | dd.MM.yyyy}}, {{time | HH:mm:ss}}, {{datetime | yy-MM-DDTHH:mm}}",
                  "example": "Signed by fidentity (this is the default if no custom text is passed)"
                },
                "image": {
                  "type": "string",
                  "title": "The base64 encoded image as Data Url (data:[<mediatype>][;base64],<data>) that will be displayed on the signature. Encoded, it should be no larger than 200Kb. Will be resized to fit the signature box. If you want the handwritten Signature as the visual Signature, you must pass an empty string and add the HandwrittenSignature Step to the processSteps array",
                  "example": "data:[<mediatype>][;base64],<data>"
                },
                "boxSize": {
                  "type": "object",
                  "title": "Total size of the visual signature box, containing the signature text and the image (in user space units = inches*72. For example: 1 inch = 2.54 cm = 72 user space units)",
                  "additionalProperties": false,
                  "properties": {
                    "width": {
                      "type": "number",
                      "title": "Width of the signature box"
                    },
                    "height": {
                      "type": "number",
                      "title": "Height of the signature box"
                    }
                  }
                }
              }
            },
            "signatureType": {
              "type": "string",
              "title": "Type of the signature, only relevant for QES case. Either 'sign' the document with QES or only 'seal' it. Useful for accompanying documents like 'terms and conditions' documents.",
              "default": "sign",
              "example": "sign",
              "enum": [
                "sign",
                "seal"
              ]
            }
          },
          "examples": [
            {
              "id": "37283719273",
              "type": "signature",
              "data": "<base 64 string>",
              "signature_position": {
                "x": 60,
                "y": 100,
                "page": 0
              },
              "visualSignature": {
                "text": "Signed by fidentity",
                "image": "<base 64 string>",
                "boxSize": {
                  "width": 300,
                  "height": 50
                }
              }
            },
            {
              "id": "37283719273",
              "type": "signature",
              "data": "<base 64 string>",
              "signature_position": {
                "placeholder": "Signature-0001"
              }
            }
          ]
        }
      }
    }
  }
}
Response 200: success
Response 401: not authenticated
Response 404: not found
Response 500: general error

Endpoint: GET /report
Summary: Get reporting data
Description: Get reporting data
Tags: report
Request Body: {
  "content": {
    "application/json": {
      "schema": {
        "type": "object",
        "properties": {
          "from": {
            "type": "string",
            "example": "2022-06-01",
            "pattern": "^([\\d\\-ZT:\\.]*)$",
            "format": "date-time"
          },
          "to": {
            "type": "string",
            "example": "2022-06-01",
            "pattern": "^([\\d\\-ZT:\\.]*)$",
            "format": "date-time"
          },
          "query": {
            "type": "string",
            "example": "qes"
          }
        }
      }
    }
  }
}
Response 200: success
Response 401: not authenticated
Response 404: not found
Response 500: general error
